blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie poznasz <strong>partitives</strong>, czyli konstrukcje pozwalające mierzyć lub porcjować rzeczowniki niepoliczalne: <strong>a piece of, a cup of, a glass of, a slice of</strong> i wiele innych.",
    "rules": [
        {
            "label": "A piece of",
            "color": "emerald",
            "text": "<strong>Kawałek / porcja / jedna sztuka</strong> czegoś:",
            "example": "a piece of cake, a piece of advice"
        },
        {
            "label": "A cup of",
            "color": "blue",
            "text": "<strong>Filiżanka / kubek</strong> napoju:",
            "example": "a cup of coffee, a cup of tea"
        },
        {
            "label": "A bottle of",
            "color": "amber",
            "text": "<strong>Butelka</strong> płynu:",
            "example": "a bottle of water, a bottle of milk"
        }
    ]
}

{
    "title": "1. Czym są partitives?",
    "intro": "To sposoby mierzenia i porcjowania rzeczowników niepoliczalnych:",
    "items": [
        {
            "label": "Containers",
            "title": "Naczynia i opakowania",
            "subtitle": "a cup of, a glass of, a bottle of pomagają nazwać porcję napoju lub zawartość pojemnika"
        },
        {
            "label": "Portions",
            "title": "Porcje i kawałki",
            "subtitle": "a piece of, a slice of, a loaf of pomagają mówić o jedzeniu i częściach czegoś"
        },
        {
            "label": "Units",
            "title": "Jednostki miary",
            "subtitle": "a kilo of, a litre of, a pound of służą do wyrażania wagi i objętości"
        }
    ]
}

{
    "title": "2. A piece of: kawałek, porcja, jedna informacja",
    "sections": [
        {
            "label": "Jedzenie",
            "color": "emerald",
            "description": "<strong>A piece of</strong> często oznacza kawałek jedzenia.",
            "examples": [
                {
                    "en": "a piece of cake",
                    "ua": "kawałek ciasta"
                },
                {
                    "en": "a piece of bread",
                    "ua": "kawałek chleba"
                },
                {
                    "en": "a piece of cheese",
                    "ua": "kawałek sera"
                },
                {
                    "en": "a piece of meat",
                    "ua": "kawałek mięsa"
                }
            ]
        },
        {
            "label": "Pojęcia abstrakcyjne",
            "color": "sky",
            "description": "To samo wyrażenie pojawia się też przy rzeczownikach takich jak advice czy information.",
            "examples": [
                {
                    "en": "a piece of advice",
                    "ua": "jedna rada"
                },
                {
                    "en": "a piece of information",
                    "ua": "jedna informacja"
                },
                {
                    "en": "a piece of news",
                    "ua": "jedna wiadomość"
                },
                {
                    "en": "a piece of evidence",
                    "ua": "jeden dowód"
                }
            ]
        },
        {
            "label": "Przedmioty i rzeczy",
            "color": "amber",
            "description": "<strong>A piece of</strong> występuje także przy niektórych rzeczach i elementach wyposażenia.",
            "examples": [
                {
                    "en": "a piece of paper",
                    "ua": "kartka papieru"
                },
                {
                    "en": "a piece of furniture",
                    "ua": "mebel / jedna sztuka mebla"
                },
                {
                    "en": "a piece of luggage",
                    "ua": "sztuka bagażu"
                },
                {
                    "en": "a piece of equipment",
                    "ua": "element wyposażenia"
                }
            ]
        }
    ]
}

{
    "title": "3. Napoje: cup, glass, bottle",
    "sections": [
        {
            "label": "A cup of",
            "color": "blue",
            "description": "<strong>A cup of</strong> najczęściej łączymy z gorącymi napojami podawanymi w filiżance albo kubku.",
            "examples": [
                {
                    "en": "a cup of coffee",
                    "ua": "filiżanka kawy"
                },
                {
                    "en": "a cup of tea",
                    "ua": "filiżanka herbaty"
                },
                {
                    "en": "a cup of hot chocolate",
                    "ua": "kubek gorącej czekolady"
                },
                {
                    "en": "two cups of coffee",
                    "ua": "dwie filiżanki kawy"
                }
            ]
        },
        {
            "label": "A glass of",
            "color": "sky",
            "description": "<strong>A glass of</strong> stosujemy przy płynach podawanych w szklance.",
            "examples": [
                {
                    "en": "a glass of water",
                    "ua": "szklanka wody"
                },
                {
                    "en": "a glass of juice",
                    "ua": "szklanka soku"
                },
                {
                    "en": "a glass of milk",
                    "ua": "szklanka mleka"
                },
                {
                    "en": "a glass of wine",
                    "ua": "kieliszek wina"
                }
            ]
        },
        {
            "label": "A bottle of",
            "color": "purple",
            "description": "<strong>A bottle of</strong> oznacza płyn albo napój w butelce.",
            "examples": [
                {
                    "en": "a bottle of water",
                    "ua": "butelka wody"
                },
                {
                    "en": "a bottle of milk",
                    "ua": "butelka mleka"
                },
                {
                    "en": "a bottle of wine",
                    "ua": "butelka wina"
                },
                {
                    "en": "a bottle of beer",
                    "ua": "butelka piwa"
                }
            ]
        }
    ]
}

{
    "title": "4. Porcje jedzenia: slice, loaf, bar",
    "sections": [
        {
            "label": "A slice of",
            "color": "emerald",
            "description": "<strong>A slice of</strong> oznacza plaster, kromkę albo kawałek odkrojony z większej całości.",
            "examples": [
                {
                    "en": "a slice of bread",
                    "ua": "kromka chleba"
                },
                {
                    "en": "a slice of pizza",
                    "ua": "kawałek pizzy"
                },
                {
                    "en": "a slice of cheese",
                    "ua": "plaster sera"
                },
                {
                    "en": "a slice of cake",
                    "ua": "kawałek ciasta"
                }
            ]
        },
        {
            "label": "A loaf of",
            "color": "amber",
            "description": "<strong>A loaf of</strong> używamy głównie przy chlebie.",
            "examples": [
                {
                    "en": "a loaf of bread",
                    "ua": "bochenek chleba"
                },
                {
                    "en": "two loaves of bread",
                    "ua": "dwa bochenki chleba"
                }
            ]
        },
        {
            "label": "A bar of",
            "color": "rose",
            "description": "<strong>A bar of</strong> pasuje do rzeczy w formie tabliczki albo kostki.",
            "examples": [
                {
                    "en": "a bar of chocolate",
                    "ua": "tabliczka czekolady"
                },
                {
                    "en": "a bar of soap",
                    "ua": "kostka mydła"
                }
            ]
        }
    ]
}

{
    "title": "5. Opakowania: box, can, jar",
    "sections": [
        {
            "label": "A box of",
            "color": "purple",
            "description": "<strong>A box of</strong> oznacza coś zapakowanego w pudełko.",
            "examples": [
                {
                    "en": "a box of chocolates",
                    "ua": "pudełko czekoladek"
                },
                {
                    "en": "a box of cereal",
                    "ua": "pudełko płatków śniadaniowych"
                },
                {
                    "en": "a box of tissues",
                    "ua": "pudełko chusteczek"
                }
            ]
        },
        {
            "label": "A can of",
            "color": "sky",
            "description": "<strong>A can of</strong> odnosi się do konserw albo napojów w puszce.",
            "examples": [
                {
                    "en": "a can of soup",
                    "ua": "puszka zupy"
                },
                {
                    "en": "a can of beans",
                    "ua": "puszka fasoli"
                },
                {
                    "en": "a can of soda",
                    "ua": "puszka napoju gazowanego"
                }
            ]
        },
        {
            "label": "A jar of",
            "color": "emerald",
            "description": "<strong>A jar of</strong> oznacza coś w słoiku.",
            "examples": [
                {
                    "en": "a jar of jam",
                    "ua": "słoik dżemu"
                },
                {
                    "en": "a jar of honey",
                    "ua": "słoik miodu"
                },
                {
                    "en": "a jar of pickles",
                    "ua": "słoik ogórków konserwowych"
                }
            ]
        }
    ]
}

{
    "title": "6. Torby i paczki: bag, packet, carton",
    "sections": [
        {
            "label": "A bag of",
            "color": "amber",
            "description": "<strong>A bag of</strong> oznacza zawartość torby, worka albo papierowej torebki.",
            "examples": [
                {
                    "en": "a bag of sugar",
                    "ua": "torba / worek cukru"
                },
                {
                    "en": "a bag of flour",
                    "ua": "torba mąki"
                },
                {
                    "en": "a bag of rice",
                    "ua": "worek ryżu"
                },
                {
                    "en": "a bag of potatoes",
                    "ua": "worek ziemniaków"
                }
            ]
        },
        {
            "label": "A packet of",
            "color": "rose",
            "description": "<strong>A packet of</strong> pasuje do rzeczy sprzedawanych w paczce.",
            "examples": [
                {
                    "en": "a packet of crisps",
                    "ua": "paczka chipsów"
                },
                {
                    "en": "a packet of biscuits",
                    "ua": "paczka herbatników"
                },
                {
                    "en": "a packet of cigarettes",
                    "ua": "paczka papierosów"
                }
            ]
        },
        {
            "label": "A carton of",
            "color": "sky",
            "description": "<strong>A carton of</strong> oznacza karton albo kartonik z napojem lub innym produktem.",
            "examples": [
                {
                    "en": "a carton of milk",
                    "ua": "karton mleka"
                },
                {
                    "en": "a carton of juice",
                    "ua": "karton soku"
                },
                {
                    "en": "a carton of eggs",
                    "ua": "wytłaczanka jajek"
                }
            ]
        }
    ]
}

{
    "title": "7. Jednostki miary: kilo, litre, pound",
    "sections": [
        {
            "label": "A kilo of",
            "color": "purple",
            "description": "<strong>A kilo of</strong> służy do podawania wagi w kilogramach.",
            "examples": [
                {
                    "en": "a kilo of sugar",
                    "ua": "kilogram cukru"
                },
                {
                    "en": "a kilo of apples",
                    "ua": "kilogram jabłek"
                },
                {
                    "en": "two kilos of potatoes",
                    "ua": "dwa kilogramy ziemniaków"
                }
            ]
        },
        {
            "label": "A litre of",
            "color": "blue",
            "description": "<strong>A litre of</strong> podaje objętość płynu.",
            "examples": [
                {
                    "en": "a litre of water",
                    "ua": "litr wody"
                },
                {
                    "en": "a litre of milk",
                    "ua": "litr mleka"
                },
                {
                    "en": "two litres of juice",
                    "ua": "dwa litry soku"
                }
            ]
        },
        {
            "label": "A pound of",
            "color": "emerald",
            "description": "<strong>A pound of</strong> podaje wagę w funtach, czyli w jednostce używanej np. w krajach anglojęzycznych.",
            "examples": [
                {
                    "en": "a pound of butter",
                    "ua": "funt masła"
                },
                {
                    "en": "a pound of coffee",
                    "ua": "funt kawy"
                }
            ],
            "note": "1 pound to około 450 gramów."
        }
    ]
}

{
    "title": "8. Inne przydatne partitives",
    "sections": [
        {
            "label": "A bowl of",
            "color": "sky",
            "description": "<strong>A bowl of</strong> oznacza zawartość miski.",
            "examples": [
                {
                    "en": "a bowl of soup",
                    "ua": "miska zupy"
                },
                {
                    "en": "a bowl of cereal",
                    "ua": "miska płatków"
                },
                {
                    "en": "a bowl of rice",
                    "ua": "miska ryżu"
                }
            ]
        },
        {
            "label": "A spoonful of",
            "color": "amber",
            "description": "<strong>A spoonful of</strong> to ilość mieszcząca się na jednej łyżce.",
            "examples": [
                {
                    "en": "a spoonful of sugar",
                    "ua": "łyżka cukru"
                },
                {
                    "en": "a spoonful of honey",
                    "ua": "łyżka miodu"
                }
            ]
        },
        {
            "label": "A drop of",
            "color": "rose",
            "description": "<strong>A drop of</strong> oznacza kroplę płynu.",
            "examples": [
                {
                    "en": "a drop of water",
                    "ua": "kropla wody"
                },
                {
                    "en": "a drop of milk",
                    "ua": "kropla mleka"
                }
            ]
        }
    ]
}

{
    "title": "9. Tabela porównawcza partitives",
    "intro": "Najczęstsze konstrukcje i ich użycie:",
    "rows": [
        {
            "en": "A piece of",
            "ua": "Kawałek / jedna sztuka",
            "note": "cake, bread, advice, information, furniture"
        },
        {
            "en": "A cup of",
            "ua": "Filiżanka / kubek",
            "note": "coffee, tea, hot chocolate"
        },
        {
            "en": "A glass of",
            "ua": "Szklanka / kieliszek",
            "note": "water, juice, milk, wine"
        },
        {
            "en": "A bottle of",
            "ua": "Butelka",
            "note": "water, milk, wine, beer"
        },
        {
            "en": "A slice of",
            "ua": "Kromka / plaster / kawałek",
            "note": "bread, pizza, cheese, cake"
        },
        {
            "en": "A loaf of",
            "ua": "Bochenek",
            "note": "bread (w liczbie mnogiej: loaves)"
        },
        {
            "en": "A bar of",
            "ua": "Tabliczka / kostka",
            "note": "chocolate, soap"
        }
    ],
    "warning": "Po partitive zawsze pojawia się <strong>of</strong> + rzeczownik."
}

{
    "title": "10. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak of po partitive.",
            "wrong": "I need a piece advice.",
            "right": "✅ <span class=\"font-mono\">I need a piece of advice.<\/span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Niepoprawna liczba mnoga.",
            "wrong": "two loafs of bread",
            "right": "✅ <span class=\"font-mono\">two loaves of bread<\/span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zły wybór partitive.",
            "wrong": "a slice of milk",
            "right": "✅ <span class=\"font-mono\">a glass of milk / a bottle of milk<\/span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Próba policzenia rzeczownika niepoliczalnego bez odpowiedniej konstrukcji.",
            "wrong": "I need a water.",
            "right": "✅ <span class=\"font-mono\">I need a glass of water. / I need some water.<\/span>"
        }
    ]
}

{
    "title": "12. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawne wyrażenie",
    "select_intro": "Wybierz konstrukcję, która najlepiej pasuje do rzeczownika.",
    "selects": [
        {
            "label": "I need ___ advice. (a piece of / a cup of)",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "Can I have ___ water? (a slice of / a glass of)",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "She bought ___ bread. (a loaf of / a bottle of)",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "I want ___ chocolate. (a slice of / a bar of)",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "Pierwsza opcja",
        "Druga opcja"
    ],
    "input_title": "Ćwiczenie 2. Uzupełnij wyrażenia",
    "input_intro": "Wpisz poprawny partitive z of.",
    "inputs": [
        {
            "before": "I need ___ information.",
            "after": "→"
        },
        {
            "before": "Can I have ___ coffee?",
            "after": "→"
        },
        {
            "before": "She bought ___ jam.",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w konstrukcji z partitive.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "I need a advice.",
            "example_target": "I need a piece of advice. / I need some advice."
        },
        {
            "original": "1. Can I have a cup coffee?",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "2. She bought two loafs of bread.",
            "placeholder": "Popraw zdanie"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Partitives",
            "current": true
        },
        {
            "label": "Quantifiers",
            "current": false
        },
        {
            "label": "Countable vs Uncountable",
            "current": false
        },
        {
            "label": "Articles",
            "current": false
        }
    ]
}
